INSERT INTO `applications` (`id`, `user_id`, `job_id`, `status`, `cover_letter`, `applied_at`) VALUES
(7, 20, 52, 'applied', 'Google?\r\nTip: Don’t create an App Password unless the app or device you want to connect to your account doesn’t have “Sign in with Google.”\r\n\r\nCreate & use App Passwords\r\nIf you use 2-Step-Verification and get a \"password incorrect\" error when you sign in Or if a device/app you want to connect to doesn’t have “Sign In with Google” option then you should use App Passwords\r\n\r\nGo to your Google Account.\r\nSelect Security.\r\nUnder \"Signing in to Google,\" select App Passwords. You may need to sign in. If you don’t have this option, it might be because:\r\n2-Step Verification is not set up for your account.\r\n2-Step Verification is only set up for security keys.\r\nYour account is through work, school, or other organization.\r\nYou turned on Advanced Protection.\r\nAt the bottom, choose Select app and choose Mail › Select device and choose Other (Custom Name) and in the custom name enter “Clodura.AI” › Generate.\r\nFollow the instructions to enter the App Password. The App Password is the 16- character code in the yellow bar on your device.\r\nTap Done.\r\nWhen to use App Pa', '2026-04-15 11:39:26');

