INSERT INTO `jobs` (`id`, `employer_id`, `title`, `company`, `location`, `salary`, `type`, `category`, `description`, `created_at`, `is_promoted`, `approval_status`) VALUES
(1, NULL, 'Biomedical Scientist', 'MediLab UK', 'Leeds', 42000, 'Full-time', 'Healthcare', 'Job Summary:\r\n\r\nMediLab UK is seeking a skilled Biomedical Scientist to join our team in Leeds. In this full-time position, you will play a key role in the Healthcare function, contributing to high-quality outcomes, operational excellence, and continuous improvement across the organisation.\r\n\r\nKey Responsibilities:\r\n- Deliver high-quality biomedical scientist services in line with clinical and professional standards.\r\n- Assess, document, and communicate findings clearly to support safe and effective outcomes.\r\n- Collaborate with multidisciplinary teams to coordinate care, planning, or service delivery.\r\n- Maintain accurate records and ensure compliance with healthcare policies and regulations.\r\n- Promote continuous improvement through evidence-based practice and quality assurance.\r\n\r\nKey Qualifications:\r\n- Relevant qualification and practical experience in biomedical scientist or related healthcare practice.\r\n- Strong understanding of professional standards, safeguarding, and compliance requirements.\r\n- Excellent communication, organisation, and patient/service-user focused approach.\r\n- Ability to work effectively both independently and within multidisciplinary teams.\r\n- Confidence using digital systems for records, reporting, and service coordination.\r\n\r\nBenefits:\r\n- Salary: £42,000 per year.\r\n- Competitive annual salary aligned with experience and market standards.\r\n- Ongoing professional development and structured training opportunities.\r\n- Full-time role with a supportive and collaborative team environment.\r\n- Access to modern tools, systems, and resources needed for success.\r\n- Career progression opportunities within a growing organisation.\r\n- Pension scheme and standard employee benefits package.', '2026-03-11 10:00:00', 1, 'approved'),
(2, NULL, 'Senior Biomedical Scientist', 'HealthCore Labs', 'Manchester', 55000, 'Full-time', 'Healthcare', 'Job Summary:\r\n\r\nHealthCore Labs is seeking a skilled Senior Biomedical Scientist to join our team in Manchester. In this full-time position, you will play a key role in the Healthcare function, contributing to high-quality outcomes, operational excellence, and continuous improvement across the organisation.\r\n\r\nKey Responsibilities:\r\n- Deliver high-quality senior biomedical scientist services in line with clinical and professional standards.\r\n- Assess, document, and communicate findings clearly to support safe and effective outcomes.\r\n- Collaborate with multidisciplinary teams to coordinate care, planning, or service delivery.\r\n- Maintain accurate records and ensure compliance with healthcare policies and regulations.\r\n- Promote continuous improvement through evidence-based practice and quality assurance.\r\n\r\nKey Qualifications:\r\n- Relevant qualification and practical experience in senior biomedical scientist or related healthcare practice.\r\n- Strong understanding of professional standards, safeguarding, and compliance requirements.\r\n- Excellent communication, organisation, and patient/service-user focused approach.\r\n- Ability to work effectively both independently and within multidisciplinary teams.\r\n- Confidence using digital systems for records, reporting, and service coordination.\r\n\r\nBenefits:\r\n- Salary: £55,000 per year.\r\n- Competitive annual salary aligned with experience and market standards.\r\n- Ongoing professional development and structured training opportunities.\r\n- Full-time role with a supportive and collaborative team environment.\r\n- Access to modern tools, systems, and resources needed for success.\r\n- Career progression opportunities within a growing organisation.\r\n- Pension scheme and standard employee benefits package.', '2026-03-11 10:00:00', 1, 'approved'),
(3, NULL, 'Clinical Biomedical Researcher', 'BioResearch Ltd', 'London', 48000, 'Full-time', 'Healthcare', 'Job Summary:\r\n\r\nBioResearch Ltd is seeking a skilled Clinical Biomedical Researcher to join our team in London. In this full-time position, you will play a key role in the Healthcare function, contributing to high-quality outcomes, operational excellence, and continuous improvement across the organisation.\r\n\r\nKey Responsibilities:\r\n- Deliver high-quality clinical biomedical researcher services in line with clinical and professional standards.\r\n- Assess, document, and communicate findings clearly to support safe and effective outcomes.\r\n- Collaborate with multidisciplinary teams to coordinate care, planning, or service delivery.\r\n- Maintain accurate records and ensure compliance with healthcare policies and regulations.\r\n- Promote continuous improvement through evidence-based practice and quality assurance.\r\n\r\nKey Qualifications:\r\n- Relevant qualification and practical experience in clinical biomedical researcher or related healthcare practice.\r\n- Strong understanding of professional standards, safeguarding, and compliance requirements.\r\n- Excellent communication, organisation, and patient/service-user focused approach.\r\n- Ability to work effectively both independently and within multidisciplinary teams.\r\n- Confidence using digital systems for records, reporting, and service coordination.\r\n\r\nBenefits:\r\n- Salary: £48,000 per year.\r\n- Competitive annual salary aligned with experience and market standards.\r\n- Ongoing professional development and structured training opportunities.\r\n- Full-time role with a supportive and collaborative team environment.\r\n- Access to modern tools, systems, and resources needed for success.\r\n- Career progression opportunities within a growing organisation.\r\n- Pension scheme and standard employee benefits package.', '2026-03-11 10:00:00', 0, 'approved'),
(4, NULL, 'Business Manager', 'BrightPath Consulting', 'London', 60000, 'Full-time', 'Business', 'Job Summary:\r\n\r\nBrightPath Consulting is seeking a skilled Business Manager to join our team in London. In this full-time position, you will play a key role in the Business function, contributing to high-quality outcomes, operational excellence, and continuous improvement across the organisation.\r\n\r\nKey Responsibilities:\r\n- Lead and deliver key business manager activities that support growth, performance, and strategic objectives.\r\n- Analyse trends, metrics, and stakeholder feedback to inform decision-making.\r\n- Develop and execute plans that improve outcomes, efficiency, and customer/client value.\r\n- Collaborate across departments to ensure aligned priorities and timely delivery.\r\n- Report progress clearly and drive continuous improvement initiatives.\r\n\r\nKey Qualifications:\r\n- Relevant qualification or proven experience in business manager and related business functions.\r\n- Strong analytical thinking and commercial awareness.\r\n- Excellent communication, presentation, and stakeholder-management skills.\r\n- Ability to lead initiatives and manage competing priorities effectively.\r\n- Results-driven mindset with focus on quality and measurable impact.\r\n\r\nBenefits:\r\n- Salary: £60,000 per year.\r\n- Competitive annual salary aligned with experience and market standards.\r\n- Ongoing professional development and structured training opportunities.\r\n- Full-time role with a supportive and collaborative team environment.\r\n- Access to modern tools, systems, and resources needed for success.\r\n- Career progression opportunities within a growing organisation.\r\n- Pension scheme and standard employee benefits package.', '2026-03-11 10:00:00', 1, 'approved'),
(5, NULL, 'Car Mechanic', 'AutoFix Garage', 'Bradford', 32000, 'Full-time', 'Automotive', 'Job Summary:\r\n\r\nAutoFix Garage is seeking a skilled Car Mechanic to join our team in Bradford. In this full-time position, you will play a key role in the Automotive function, contributing to high-quality outcomes, operational excellence, and continuous improvement across the organisation.\r\n\r\nKey Responsibilities:\r\n- Deliver high-quality work as a car mechanic in line with organisational standards and objectives.\r\n- Manage day-to-day responsibilities efficiently while maintaining service quality.\r\n- Collaborate with colleagues and stakeholders to ensure smooth operations.\r\n- Maintain accurate documentation and follow relevant policies and procedures.\r\n- Identify opportunities to improve processes and overall performance.\r\n\r\nKey Qualifications:\r\n- Relevant experience or training for the car mechanic role.\r\n- Strong organisation, communication, and problem-solving skills.\r\n- Ability to work independently and as part of a collaborative team.\r\n- Attention to detail and commitment to quality outcomes.\r\n- Professional approach with adaptability in a dynamic environment.\r\n\r\nBenefits:\r\n- Salary: £32,000 per year.\r\n- Competitive annual salary aligned with experience and market standards.\r\n- Ongoing professional development and structured training opportunities.\r\n- Full-time role with a supportive and collaborative team environment.\r\n- Access to modern tools, systems, and resources needed for success.\r\n- Career progression opportunities within a growing organisation.\r\n- Pension scheme and standard employee benefits package.', '2026-03-11 10:00:00', 0, 'approved'),
(6, NULL, 'Retail Cashier', 'QuickMart Stores', 'Leeds', 24000, 'Full-time', 'Retail', 'Job Summary:\r\n\r\nQuickMart Stores is seeking a skilled Retail Cashier to join our team in Leeds. In this full-time position, you will play a key role in the Retail function, contributing to high-quality outcomes, operational excellence, and continuous improvement across the organisation.\r\n\r\nKey Responsibilities:\r\n- Design, build, and maintain reliable solutions as a retail cashier to meet business and user needs.\r\n- Translate requirements into scalable implementations with strong quality and security practices.\r\n- Troubleshoot issues, optimise performance, and ensure stable production operations.\r\n- Collaborate with cross-functional teams to deliver features and improvements on schedule.\r\n- Document work clearly and contribute to technical standards and continuous improvement.\r\n\r\nKey Qualifications:\r\n- Relevant qualification or hands-on experience in retail cashier and related technologies.\r\n- Strong problem-solving ability with attention to maintainability and performance.\r\n- Understanding of secure, reliable, and testable delivery practices.\r\n- Effective teamwork and communication across technical and non-technical stakeholders.\r\n- Ability to prioritise work and adapt in a fast-paced environment.\r\n\r\nBenefits:\r\n- Salary: £24,000 per year.\r\n- Competitive annual salary aligned with experience and market standards.\r\n- Ongoing professional development and structured training opportunities.\r\n- Full-time role with a supportive and collaborative team environment.\r\n- Access to modern tools, systems, and resources needed for success.\r\n- Career progression opportunities within a growing organisation.\r\n- Pension scheme and standard employee benefits package.', '2026-03-11 10:00:00', 0, 'approved'),
(7, NULL, 'University CEO', 'Bradford Academic Group', 'Bradford', 95000, 'Full-time', 'Education', 'Job Summary:\r\n\r\nBradford Academic Group is seeking a skilled University CEO to join our team in Bradford. In this full-time position, you will play a key role in the Education function, contributing to high-quality outcomes, operational excellence, and continuous improvement across the organisation.\r\n\r\nKey Responsibilities:\r\n- Deliver high-quality work as a university ceo in line with organisational standards and objectives.\r\n- Manage day-to-day responsibilities efficiently while maintaining service quality.\r\n- Collaborate with colleagues and stakeholders to ensure smooth operations.\r\n- Maintain accurate documentation and follow relevant policies and procedures.\r\n- Identify opportunities to improve processes and overall performance.\r\n\r\nKey Qualifications:\r\n- Relevant experience or training for the university ceo role.\r\n- Strong organisation, communication, and problem-solving skills.\r\n- Ability to work independently and as part of a collaborative team.\r\n- Attention to detail and commitment to quality outcomes.\r\n- Professional approach with adaptability in a dynamic environment.\r\n\r\nBenefits:\r\n- Salary: £95,000 per year.\r\n- Competitive annual salary aligned with experience and market standards.\r\n- Ongoing professional development and structured training opportunities.\r\n- Full-time role with a supportive and collaborative team environment.\r\n- Access to modern tools, systems, and resources needed for success.\r\n- Career progression opportunities within a growing organisation.\r\n- Pension scheme and standard employee benefits package.', '2026-03-11 10:00:00', 1, 'approved'),
(8, NULL, 'Civil Engineer', 'UrbanBuild Ltd', 'Leeds', 50000, 'Full-time', 'Engineering', 'Job Summary:\r\n\r\nUrbanBuild Ltd is seeking a skilled Civil Engineer to join our team in Leeds. In this full-time position, you will play a key role in the Engineering function, contributing to high-quality outcomes, operational excellence, and continuous improvement across the organisation.\r\n\r\nKey Responsibilities:\r\n- Plan, design, or deliver civil engineer tasks to agreed technical, quality, and safety standards.\r\n- Review specifications, drawings, and project requirements to ensure practical implementation.\r\n- Monitor progress, identify risks early, and implement effective corrective actions.\r\n- Coordinate with stakeholders, contractors, and internal teams to meet delivery timelines.\r\n- Support continuous improvement in technical processes, documentation, and compliance.\r\n\r\nKey Qualifications:\r\n- Degree, certification, or equivalent experience relevant to civil engineer responsibilities.\r\n- Strong technical problem-solving skills and attention to detail.\r\n- Good knowledge of applicable standards, regulations, and safe working practices.\r\n- Effective communication and teamwork across technical and non-technical stakeholders.\r\n- Proficiency with relevant engineering/project tools and reporting methods.\r\n\r\nBenefits:\r\n- Salary: £50,000 per year.\r\n- Competitive annual salary aligned with experience and market standards.\r\n- Ongoing professional development and structured training opportunities.\r\n- Full-time role with a supportive and collaborative team environment.\r\n- Access to modern tools, systems, and resources needed for success.\r\n- Career progression opportunities within a growing organisation.\r\n- Pension scheme and standard employee benefits package.', '2026-03-11 10:00:00', 0, 'approved'),
